// Binary search lookup (FONT_UNICODES is sorted)
inline int fontLookup(uint16_t unicode) {
    int lo = 0, hi = FONT_CHAR_COUNT - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (FONT_UNICODES[mid] == unicode) return mid;
        if (FONT_UNICODES[mid] < unicode) lo = mid + 1;
        else hi = mid - 1;
    }
    return -1;
}